private:
	map<string, FileStruct> files;

public:
	bool createFile(const string& id, int size) {
		if (files.find(id) != files.end()) {
			return false;
		}
		files[id] = {id, size};
		return true;
	}

	bool deleteFile(const string& id) {
		auto it = files.find(id);
		if (it == files.end()) {
			return false;
		}
		files.erase(it);
		return true;
	}

	void listFiles() {
		cout << "Files:" << endl;
		for (const auto& pair : files) {
			cout << "\tID: " << pair.second.id << ", Size: " << pair.second.size << " KB" << endl;
		}
	}
};

