class InventoryManager:
    """Manages an inventory of products with methods to add, remove, and list products."""

    def __init__(self):
        """Initialize an empty inventory stored as a dictionary."""
        self.inventory = {}

    def add_product(self, product):
        """Add a product to the inventory.

        Args:
            product (dict): Dictionary with 'product_id', 'name', and 'quantity' keys.

        Raises:
            ValueError: If product exists, has negative quantity, or lacks required keys.
        """
        required_keys = {'product_id', 'name', 'quantity'}
        if not all(key in product for key in required_keys):
            raise ValueError("Product missing required keys.")
        product_id = product['product_id']
        if product_id in self.inventory:
            raise ValueError(f"Product {product_id} already exists.")
        if product['quantity'] < 0:
            raise ValueError("Quantity cannot be negative.")
        self.inventory[product_id] = product

    def remove_product(self, product_id, quantity):
        """Remove a specified quantity from a product's stock.

        Args:
            product_id (int): ID of the product to adjust.
            quantity (int): Non-negative quantity to remove.

        Raises:
            ValueError: If product not found, negative quantity, or insufficient stock.
        """
        if product_id not in self.inventory:
            raise ValueError("Product not found.")
        if quantity < 0:
            raise ValueError("Cannot remove negative quantity.")
        current_quantity = self.inventory[product_id]['quantity']
        if current_quantity < quantity:
            raise ValueError("Insufficient quantity to remove.")
        self.inventory[product_id]['quantity'] -= quantity

    def list_products(self):
        """Return a list of all products in the inventory.

        Returns:
            list: List of product dictionaries.
        """
        return list(self.inventory.values())
