package main

import (
  "crypto/md5"
  "encoding/base64"
  "fmt"
  "net/url"
)

type URLShortener struct {
  originalURL string
  shortURL    string
  urlMap      map[string]string
}

func (u *URLShortener) StoreURL(original string) error {
  _, err := url.ParseRequestURI(original)
  if err != nil {
    return fmt.Errorf("invalid URL: %v", err)
  }

  short := generateShortURL(original)
  u.originalURL = original
  u.shortURL = short
  if u.urlMap == nil {
    u.urlMap = make(map[string]string)
  }
  u.urlMap[short] = original
  return nil
}

func (u *URLShortener) RetrieveURL(short string) (string, error) {
  original, exists := u.urlMap[short]
  if !exists {
    return "", fmt.Errorf("short URL not found")
  }
  return original, nil
}

func generateShortURL(original string) string {
  hash := md5.Sum([]byte(original))
  encoded := base64.URLEncoding.EncodeToString(hash[:])
  if len(encoded) < 6 {
    return encoded
  }
  return encoded[:6]
}
