            raise

    def process_data(self, data, sensitive_fields):
        try:
            processed_data = []
            for record in data:
                filtered = {k: v for k, v in record.items() if k not in sensitive_fields}
                processed_data.append(filtered)
            self._log("Data processed successfully")
            return processed_data
        except Exception as e:
            self._log(f"Data processing error: {str(e)}", error=True)
            raise

    def upload_file(self, local_path, cloud_path, sensitive_fields=None):
        if not self.is_authenticated:
            raise PermissionError("Authentication required before upload")
        try:
            with open(local_path, 'r') as file:
                data = file.readlines()
            processed_data = self.process_data(data, sensitive_fields or [])
            self._log(f"Uploaded {local_path} to {cloud_path}")
        except FileNotFoundError:
            self._log(f"File not found: {local_path}", error=True)
            raise
        except PermissionError:
            self._log("Permission denied during upload", error=True)
            raise
        except Exception as e:
            self._log(f"Upload error: {str(e)}", error=True)
            raise

    def _log(self, message, error=False):
        timestamp = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        log_entry = f"{timestamp} - {'ERROR' if error else 'INFO'} - {message}\n"
        with open(self.log_file, 'a') as log_file:
