use std::collections::HashMap;
use std::fmt;

#[derive(Debug)]
pub enum ConfigError {
  Io(std::io::Error),
  Parse(String),
}

impl fmt::Display for ConfigError {
  fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
    match self {
      ConfigError::Io(e) => write!(f, "IO error: {}", e),
      ConfigError::Parse(msg) => write!(f, "Parse error: {}", msg),
    }
  }
}

impl From<std::io::Error> for ConfigError {
  fn from(err: std::io::Error) -> Self {
    ConfigError::Io(err)
  }
}

pub fn load_configuration(path: &str) -> Result<HashMap<String, String>, ConfigError> {
  let content = std::fs::read_to_string(path)?;
  let mut config = HashMap::new();
  for (line_num, line) in content.lines().enumerate() {
    let line = line.trim();
    if line.is_empty() || line.starts_with('#') {
      continue;
    }
    let (key, value) = line.split_once('=')
      .ok_or_else(|| ConfigError::Parse(format!("Line {}: invalid format", line_num + 1)))?;
    let key = key.trim().to_string();
    let value = value.trim().to_string();
    if key.is_empty() {
      return Err(ConfigError::Parse(format!("Line {}: missing key", line_num + 1)));
    }
    config.insert(key, value);
  }
  Ok(config)
}
