#include <vector>

class MatrixMultiplier {
public:
    static std::vector<std::vector<int>> MultiplyMatrices(std::vector<std::vector<int>> a, std::vector<std::vector<int>> b) {
        int rows_a = a.size();
        int cols_a = a[0].size();
        int cols_b = b[0].size();
        std::vector<std::vector<int>> result(rows_a, std::vector<int>(cols_b, 0));
        for (int i = 0; i < rows_a; ++i) {
            for (int j = 0; j < cols_b; ++j) {
                for (int k = 0; k < cols_a; ++k) {
                    result[i][j] += a[i][k] * b[k][j];
                }
            }
        }
        return result;
    }
};
